class Solution {
    public int primePalindrome(int n) {
        while (true) {
            if (isPalindrome(n) && isPrime(n)) {
                return n;
            }
            n++;
        }
    }

    private boolean isPalindrome(int num) {
        int reversed = 0;
        int original = num;
        while (num != 0) {
            int pop = num % 10;
            num /= 10;
            reversed = reversed * 10 + pop;
        }
        return original == reversed;
    }

    private boolean isPrime(int num) {
        if (num <= 1) {
            return false;
        }
        for (int i = 2; i * i <= num; i++) {
            if (num % i == 0) {
                return false;
            }
        }
        return true;
    }
}
